using Skojjt.Core.Exports;
using Skojjt.Core.Exports.Validation;
using Skojjt.Core.Services;
using Skojjt.Infrastructure.Exports;

// Needed for DakParseResult, DakComparisonResult, DakData
using DakParseResult = Skojjt.Core.Exports.DakParseResult;
using DakComparisonResult = Skojjt.Core.Exports.DakComparisonResult;
using DakData = Skojjt.Core.Exports.DakData;namespace Skojjt.Infrastructure.Services;/// <summary>/// Service for analyzing DAK XML files: parse, normalize, compare, and validate./// </summary>public class DakAnalysisService : IDakAnalysisService{    public DakParseResult Parse(Stream stream, string fileName = "") =>        DakXmlReader.Parse(stream, fileName);    public DakParseResult Parse(byte[] data, string fileName = "") =>        DakXmlReader.Parse(data, fileName);    public DakComparisonResult Compare(DakData old, DakData @new)    {        DakNormalizer.Normalize(old);        DakNormalizer.Normalize(@new);        return DakComparer.Compare(old, @new);    }    public AktivitetsbidragResult Validate(DakData dak, AktivitetsbidragSettings? settings, int terminsAr)    {        settings ??= AktivitetsbidragKnownSettings.FindSettings(dak.KommunId, terminsAr);        if (settings is null)        {            return new AktivitetsbidragResult            {                Issues =                [                    new DakParseIssue                    {                        Severity = DakIssueSeverity.Error,                        Message = $"Inga bidragsinställningar hittades för kommun '{dak.KommunId}', år {terminsAr}. " +                                  "Välj inställningar manuellt.",                        XmlPath = "Kommun",                        ActualValue = dak.KommunId,                    }                ],                Summering = new BidragsSummering                {                    SammankomstBerakningar = [],                    Settings = AktivitetsbidragKnownSettings.Goteborg2026, // fallback for type safety                    TerminsAr = terminsAr,                },            };        }        return AktivitetsbidragValidator.Validate(dak, settings, terminsAr);    }}